import { Link } from "react-router-dom";
import "./NotFound.css";

function NotFound() {
  return (
    <div className="notfound-container">

      <h2>Oops! The page you are looking for has been removed or relocated</h2>
      <Link to="/">
      
        <button>Go Back</button>
      </Link>
    </div>
  );
}

export default NotFound;
